INSERT INTO public.game_cards (card_type, source, name, content, metadata) VALUES
('domain', 'Beast Shape', 'Beast Shape: Agile Scout', E'**Trait & Evasion:** Agility +1, Evasion +2\n**Attack:** Melee Agility d4 phy\n**Advantage:** Gain advantage on: deceive, locate, sneak\n\n**Agile: Your movement is silent, and you can spend a Hope to move up to Far range without rolling.**\n\n**Fragile: When you take Major or greater damage, you drop out of Beastform.**', '{"level": 1, "recall_cost": 1, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Nimble Grazer', E'**Trait & Evasion:** Agility +1, Evasion +3\n**Attack:** Melee Agility d6 phy\n**Advantage:** Gain advantage on: leap, sneak, sprint\n\n**Elusive Prey: When an attack roll against you would succeed, you can mark a Stress and roll a d4. Add your result to Evasion against this attack.**\n\n**Fragile: When you take Major or greater damage, you drop out of Beastform.**', '{"level": 1, "recall_cost": 1, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Aquatic Scout', E'**Trait & Evasion:** Agility +1, Evasion +2\n**Attack:** Melee Agility d4 phy\n**Advantage:** Gain advantage on: navigate, sneak, swim\n\n**Aquatic: You can breathe and move normally underwater.**\n\n**Fragile: When you take Major or greater damage, you drop out of Beastform.**', '{"level": 1, "recall_cost": 1, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Household Friend', E'**Trait & Evasion:** Instinct +1, Evasion +2\n**Attack:** Melee Instinct d6 phy\n**Advantage:** Gain advantage on: climb, locate, protect\n\n**Companion: When you Help an Ally, you can roll a d8 as your advantage die.**\n\n**Fragile: When you take Major or greater damage, you drop out of Beastform.**', '{"level": 1, "recall_cost": 1, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Pack Predator', E'**Trait & Evasion:** Strength +2, Evasion +1\n**Attack:** Melee Strength d8+2 phy\n**Advantage:** Gain advantage on: attack, sprint, track\n\n**Hobbling Strike: When you succeed on an attack against a target within Melee range, you can mark a Stress to temporarily make the target Vulnerable.**\n\n**Pack Hunting: When you succeed on an attack against the same target as an ally who acts immediately before you, add a d8 to your damage roll.**', '{"level": 1, "recall_cost": 1, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Stalking Arachnid', E'**Trait & Evasion:** Finesse +1, Evasion +2\n**Attack:** Melee Finesse d6+1 phy\n**Advantage:** Gain advantage on: attack, climb, sneak\n\n**Venomous Bite: When you succeed on an attack against a target within Melee range the target becomes temporarily Poisoned. A Poisoned creature takes 1d10 direct physical damage each time they act.**\n\n**Webslinger: You can create a strong web material useful for both adventure and battling. The web is resilient enough to support one creature. You can temporarily Restrain a target within Close range by succeeding on a Finesse Roll against them.**', '{"level": 1, "recall_cost": 1, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Armored Sentry', E'**Trait & Evasion:** Strength +1, Evasion +1\n**Attack:** Melee Strength d8+2 phy\n**Advantage:** Gain advantage on: dig, locate, protect\n\n**Armored Shell: Your hardened exterior gives you resistance to physical damage. Additionally, mark an Armor Slot to retract into your shell. While in your shell, physical damage is reduced by a number equal to your Armor Score (after applying resistance), but you can''t perform other actions without leaving this form.**\n\n**Cannonball: Mark a Stress to allow an ally to throw or launch you at an adversary. To do so, the ally makes an attack roll using Agility or Strength (their choice) against a target within Close range. On a success, the adversary takes 1d12+2 physical damage using the thrower''s Proficiency. You can spend a Hope to target an additional adversary within Very Close range of the first. The second target takes half the damage dealt to the first.**', '{"level": 2, "recall_cost": 2, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Mighty Strider', E'**Trait & Evasion:** Agility +1, Evasion +2\n**Attack:** Melee Agility d8+1 phy\n**Advantage:** Gain advantage on: leap, navigate, sprint\n\n**Carrier: You can carry up to two willing allies when you move.**\n\n**Trample: Mark a Stress to move up to Close range in a straight line and make an attack against all targets within Melee range of the line. Targets you succeed against take 1d8+1 physical damage using your Proficiency and are temporarily Vulnerable.**', '{"level": 2, "recall_cost": 2, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Pouncing Predator', E'**Trait & Evasion:** Instinct +1, Evasion +3\n**Attack:** Melee Instinct d8+6 phy\n**Advantage:** Gain advantage on: attack, climb, sneak\n\n**Fleet: Spend a Hope to move up to Far range without rolling.**\n\n**Takedown: Mark a Stress to move into Melee range of target and make an attack roll against them. On a success, you gain a +2 bonus to your Proficiency for this attack and the target must mark a Stress.**', '{"level": 2, "recall_cost": 2, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Powerful Beast', E'**Trait & Evasion:** Strength +1, Evasion +3\n**Attack:** Melee Strength d10+4 phy\n**Advantage:** Gain advantage on: navigate, protect, scare\n\n**Rampage: When you roll a 1 on a damage die, you can roll a d10 and add the result to the damage roll. Additionally, before you make an attack roll, you can mark a Stress to gain a +1 bonus to your Proficiency for that attack.**\n\n**Thick Hide: You gain a +2 bonus to your damage thresholds.**', '{"level": 2, "recall_cost": 2, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Striking Serpent', E'**Trait & Evasion:** Finesse +1, Evasion +2\n**Attack:** Melee Finesse d8+4 phy\n**Advantage:** Gain advantage on: climb, deceive, sprint\n\n**Venomous Strike: Make an attack against any number of targets within Very Close range. On a success, a target is temporarily Poisoned. A Poisoned creature takes 1d10 physical direct damage each time they act.**\n\n**Warning Hiss: Mark a Stress to force any number of targets within Melee range to move back to Very Close range.**', '{"level": 2, "recall_cost": 2, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Winged Beast', E'**Trait & Evasion:** Finesse +1, Evasion +3\n**Attack:** Melee Finesse d4+2 phy\n**Advantage:** Gain advantage on: deceive, locate, scare\n\n**Bird''s-Eye View: You can fly at will. Once per rest while you are airborne, you can ask the GM a question about the scene below you without needing to roll. The first time a character makes a roll to act on this information, they gain advantage on the roll.**\n\n**Hollow Bones: You gain a -2 penalty to your damage thresholds.**', '{"level": 2, "recall_cost": 2, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Great Predator', E'**Trait & Evasion:** Strength +2, Evasion +2\n**Attack:** Melee Strength d12+8 phy\n**Advantage:** Gain advantage on: attack, sneak, sprint\n\n**Carrier: You can carry up to two willing allies when you move.**\n\n**Vicious Maul: When you succeed on an attack against a target, you can spend a Hope to make them temporarily Vulnerable and gain a +1 to your Proficiency for this attack.**', '{"level": 3, "recall_cost": 3, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Great Winged Beast', E'**Trait & Evasion:** Finesse +2, Evasion +3\n**Attack:** Melee Finesse d8+6 phy\n**Advantage:** Gain advantage on: deceive, distract, locate\n\n**Bird''s-Eye View: You can fly at will. Once per rest while you are airborne, you can ask the GM a question about the scene below you without needing to roll. The first time a character makes a roll to act on this information, they gain advantage on the roll.**\n\n**Carrier: You can carry up to two willing allies when you move.**', '{"level": 3, "recall_cost": 3, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Mighty Lizard', E'**Trait & Evasion:** Instinct +2, Evasion +1\n**Attack:** Melee Instinct d10+7 phy\n**Advantage:** Gain advantage on: attack, sneak, track\n\n**Physical Defense: You gain a +3 bonus to your damage thresholds.**\n\n**Snapping Strike: When you succeed on an attack against a target within Melee range, you can spend a Hope to clamp that opponent in your jaws, making them temporarily Restrained and Vulnerable.**', '{"level": 3, "recall_cost": 3, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Aquatic Predator', E'**Trait & Evasion:** Agility +2, Evasion +4\n**Attack:** Melee Agility d10+6 phy\n**Advantage:** Gain advantage on: attack, swim, track\n\n**Aquatic: You can breathe and move normally underwater.**\n\n**Vicious Maul: When you succeed on an attack against a target, you can spend a Hope to make them temporarily Vulnerable and gain a +1 to your Proficiency for this attack.**', '{"level": 3, "recall_cost": 3, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Legendary Hybrid', E'**Trait & Evasion:** Strength +2, Evasion +3\n**Attack:** Melee Strength d10+8 phy\n**Advantage:** Gain advantage on: (see hybrid features)\n\n**Hybrid features: To transform into this creature, mark an additional Stress. Choose any two Beastform options from tier 1-2. Choose a total of four advantages and two features from those options.**', '{"level": 3, "recall_cost": 3, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
('domain', 'Beast Shape', 'Beast Shape: Legendary Agile Scout', E'**Trait & Evasion:** Agility +2, Evasion +4\n**Attack:** Melee Agility d4+6 phy\n**Advantage:** Gain advantage on: deceive, locate, sneak\n\n**Agile: Your movement is silent, and you can spend a Hope to move up to Far range without rolling.**\n\n**Fragile: When you take Major or greater damage, you drop out of Beastform.**', '{"level": 3, "recall_cost": 3, "category": "Beast Shape", "class_restriction": "Druid"}'::jsonb),
